hooks.command:
for f in $(git diff --cached --name-only 2>/dev/null); do
  case "$f" in
    *.rs) command -v rustfmt >/dev/null 2>&1 && rustfmt "$f" 2>/dev/null || true ;;
    *.ts|*.tsx|*.js|*.jsx|*.json) command -v npx >/dev/null 2>&1 && npx prettier --write "$f" 2>/dev/null || true ;;
  esac
done
